    86→fn build_action_view(action: &NextAction, contexts: &[Context]) -> ProjectNextActionView {
    87→    let context_name = contexts
    88→        .iter()
    89→        .find(|c| c.id() == action.context_id())
    90→        .map(|c| c.name().as_str().to_string())
    91→        .unwrap_or_else(|| "Unknown".to_string());
    92→
    93→    ProjectNextActionView {
    94→        id: action.id().as_uuid().to_string(),
    95→        title: action.title().as_str().to_string(),
    96→        context_name,
    97→        is_completed: action.is_completed(),
    98→    }
    99→}
